@once<script>document.addEventListener('DOMContentLoaded',function(){var type=document.getElementById('home-destination-type'),route=document.querySelector('[data-route-destination]'),routeInput=route.querySelector('select'),external=document.querySelector('[data-external-destination]'),externalInput=document.querySelector('[data-external-value]');function sync(){var isRoute=type.value==='route',isExternal=type.value==='external_url';route.hidden=!isRoute;external.hidden=!isExternal;routeInput.disabled=!isRoute;routeInput.required=isRoute;externalInput.disabled=!isExternal;externalInput.required=isExternal;if(isExternal)externalInput.name='destination_value';else externalInput.removeAttribute('name')}type.addEventListener('change',sync);sync()})</script>@endonce
